import type { Item } from './index';

// Catálogo A — "Prompts de IA para tu negocio" (100 prompts, gratis, copiables).
// Reescritos con el framework Rol + Contexto + Tarea + Restricciones + Formato.
// `tema` agrupa cada grupo en 5 subtemas de 5 prompts (evita la "wall of cards").
export const PROMPTS: Item[] = [
  {"id":"p01","catalogo":"prompts","grupo":"Por industria","tema":"Marketing","titulo":"Copy de ventas con fórmula PAS","cuerpo":"Rol: Eres copywriter de respuesta directa con experiencia en conversión para PyMEs y campañas de venta digital.\nContexto: Vendemos [producto/servicio] a [audiencia], cuyo principal dolor es [dolor]. Buscamos un copy honesto que conecte con esa frustración y motive la acción.\nTarea: Redacta un copy de ventas usando la fórmula PAS (Problema, Agitación, Solución) que termine con una llamada a la acción clara hacia [CTA/objetivo].\nRestricciones: Tono profesional y cercano. Máximo 180 palabras. No inventes cifras, testimonios ni resultados: si hace falta un dato, deja un placeholder entre corchetes. Evita promesas exageradas o afirmaciones no verificables. Español neutro.\nFormato: Devuelve el copy en tres bloques etiquetados (Problema / Agitación / Solución) y cierra con una línea de CTA. Añade al final 3 variantes alternativas de titular (una línea cada una)."},
  {"id":"p02","catalogo":"prompts","grupo":"Por industria","tema":"Marketing","titulo":"Calendario editorial de 15 días","cuerpo":"Rol: Eres estratega de contenidos B2B especializado en embudos de marketing (ToFU/MoFU/BoFU).\nContexto: Necesito un plan de publicaciones para el nicho [nicho], equilibrado entre atracción, consideración y decisión.\nTarea: Diseña un calendario editorial de 15 días con 5 piezas ToFU, 5 MoFU y 5 BoFU.\nRestricciones: Cada pieza debe ser realista de producir por un equipo pequeño. No repitas ángulos ni títulos. Alterna canales y formatos de forma coherente con cada etapa del embudo. Español neutro, sin modismos.\nFormato: Devuelve una tabla con las columnas: Día | Etapa (ToFU/MoFU/BoFU) | Título | Canal | Formato | Objetivo. Ordena por día del 1 al 15."},
  {"id":"p03","catalogo":"prompts","grupo":"Por industria","tema":"Marketing","titulo":"3 variaciones de copy para Meta Ads","cuerpo":"Rol: Eres especialista en performance marketing y redacción de anuncios para Meta Ads (Facebook e Instagram).\nContexto: Vamos a promocionar [producto/servicio] dirigido a [audiencia]. Queremos probar tres ángulos distintos en un test A/B/C.\nTarea: Crea 3 variaciones de copy: (1) storytelling emocional, (2) datos y beneficios concretos, (3) ultracorta y directa. Cada variación con un hook inicial, un cuerpo y 3 títulos alternativos.\nRestricciones: Respeta buenas prácticas de la plataforma (sin promesas exageradas ni claims prohibidos). No inventes estadísticas: usa placeholders si necesitas un dato. El hook debe caber en las primeras 125 caracteres visibles. Español neutro.\nFormato: Para cada variación devuelve tres apartados etiquetados: Hook, Cuerpo y Títulos (lista de 3). Separa claramente las variaciones 1, 2 y 3."},
  {"id":"p04","catalogo":"prompts","grupo":"Por industria","tema":"Marketing","titulo":"SEO on-page para tu keyword","cuerpo":"Rol: Eres consultor SEO on-page con experiencia en posicionamiento de contenidos para PyMEs.\nContexto: Vamos a optimizar una página sobre [tema] cuya palabra clave objetivo es [keyword].\nTarea: Genera el título SEO, la meta descripción y la estructura de encabezados (H1, H2, H3) orientados a esa keyword y a la intención de búsqueda del usuario.\nRestricciones: Título ≤ 60 caracteres, meta descripción ≤ 155 caracteres, ambos incluyendo la keyword de forma natural. No fuerces la densidad de palabras clave ni recurras a técnicas engañosas. Español neutro.\nFormato: Devuelve: 1) Título (con recuento de caracteres), 2) Meta descripción (con recuento de caracteres), 3) Esquema jerárquico de encabezados H1/H2/H3 en lista indentada. Añade una nota breve sobre la intención de búsqueda detectada."},
  {"id":"p05","catalogo":"prompts","grupo":"Por industria","tema":"Marketing","titulo":"DM y email para micro-influencers","cuerpo":"Rol: Eres responsable de marketing de influencia especializado en colaboraciones con micro-influencers.\nContexto: Queremos proponer una colaboración de beneficio mutuo a creadores de la industria [industria] alineados con nuestra marca.\nTarea: Redacta 1) una plantilla de mensaje directo (DM) de Instagram (≤ 150 palabras) y 2) un email de seguimiento para quienes no respondan al DM.\nRestricciones: Tono cercano y respetuoso, sin sonar automatizado. Deja claro el beneficio mutuo sin prometer cifras que no controlamos. Incluye placeholders como [nombre], [marca] y [propuesta]. Español neutro.\nFormato: Devuelve dos bloques etiquetados: 'DM Instagram' (con recuento de palabras) y 'Email de seguimiento' (con línea de asunto sugerida y cuerpo)."},
  {"id":"p06","catalogo":"prompts","grupo":"Por industria","tema":"Ventas","titulo":"Correo en frío B2B para agendar llamada","cuerpo":"Rol: Eres especialista en prospección B2B y redacción de correos en frío con buenas tasas de respuesta.\nContexto: Escribimos a [puesto] de [empresa] para conseguir una llamada de 15 minutos en la que mostrar cómo [solución] resuelve [problema].\nTarea: Redacta un correo en frío de 4 párrafos: apertura personalizada, contexto del problema, propuesta de valor y llamada a la acción para agendar la llamada.\nRestricciones: Máximo 150 palabras en total. Tono profesional, directo y sin lenguaje de venta agresivo. No inventes datos sobre la empresa destinataria: usa placeholders. Evita promesas no verificables. Español neutro.\nFormato: Devuelve 1) 3 opciones de línea de asunto (≤ 50 caracteres cada una) y 2) el cuerpo del correo en 4 párrafos con una línea de CTA final."},
  {"id":"p07","catalogo":"prompts","grupo":"Por industria","tema":"Ventas","titulo":"Rebatir la objeción 'es muy caro'","cuerpo":"Rol: Eres formador de ventas consultivas experto en manejo de objeciones de precio.\nContexto: Un prospecto responde que [producto/servicio] es 'demasiado caro'. Queremos reencuadrar el precio como inversión y mostrar el retorno esperado.\nTarea: Redacta 3 respuestas persuasivas y distintas entre sí para reencuadrar esa objeción, cada una apoyada en un ángulo diferente (coste de no actuar, ROI, comparación de valor).\nRestricciones: Tono empático, nunca defensivo ni manipulador. No inventes cifras de ROI: usa placeholders como [ahorro estimado] o [periodo de amortización] para que el usuario los complete. Español neutro.\nFormato: Devuelve 3 respuestas numeradas. Bajo cada una, indica en una línea el ángulo psicológico que utiliza y cuándo conviene usarla."},
  {"id":"p08","catalogo":"prompts","grupo":"Por industria","tema":"Ventas","titulo":"Guion de llamada en frío de 2 minutos","cuerpo":"Rol: Eres coach de televenta y prospección telefónica B2B.\nContexto: Vamos a llamar en frío a [perfil] para presentar [solución]. Disponemos de unos 2 minutos antes de perder su atención.\nTarea: Escribe un guion de llamada de 2 minutos con estas secciones: apertura, gancho de dolor, propuesta de valor, manejo de una objeción probable y cierre con siguiente paso.\nRestricciones: Lenguaje natural y conversacional, frases cortas para leer en voz alta. Tono honesto, sin presión ni promesas exageradas. Incluye placeholders para nombre, empresa y dato específico. Español neutro.\nFormato: Devuelve el guion dividido en 5 secciones etiquetadas. Añade entre paréntesis breves acotaciones de tono o pausa donde ayude."},
  {"id":"p09","catalogo":"prompts","grupo":"Por industria","tema":"Ventas","titulo":"3 propuestas de valor únicas","cuerpo":"Rol: Eres estratega de posicionamiento y mensajes de marca.\nContexto: Trabajamos el posicionamiento de [negocio], cuyas características principales son [lista de características]. Queremos una propuesta de valor clara y diferenciada.\nTarea: Redacta 3 fórmulas de propuesta de valor única siguiendo el patrón: 'Ayudamos a [audiencia] a [beneficio] sin [dolor]'.\nRestricciones: Cada fórmula debe destacar un beneficio distinto y ser creíble, sin superlativos vacíos ni afirmaciones no verificables. Máximo 25 palabras por fórmula. Español neutro.\nFormato: Devuelve 3 opciones numeradas. Bajo cada una, añade una línea que explique a qué segmento o motivación apela."},
  {"id":"p10","catalogo":"prompts","grupo":"Por industria","tema":"Ventas","titulo":"Conexión y seguimiento en LinkedIn","cuerpo":"Rol: Eres experto en social selling y desarrollo de negocio en LinkedIn.\nContexto: Queremos conectar con [perfil] para iniciar una conversación en torno a [tema], sin sonar comerciales desde el primer mensaje.\nTarea: Redacta 1) un mensaje de solicitud de conexión (< 300 caracteres, no vendedor) y 2) un primer mensaje de seguimiento de unas 100 palabras tras aceptar la conexión.\nRestricciones: Tono humano y genuino, centrado en aportar valor o conversación, no en vender. No inventes datos del perfil: usa placeholders como [detalle observado]. Español neutro.\nFormato: Devuelve dos bloques etiquetados: 'Solicitud de conexión' (con recuento de caracteres) y 'Primer seguimiento' (con recuento de palabras)."},
  {"id":"p11","catalogo":"prompts","grupo":"Por industria","tema":"Tecnología","titulo":"Revisión de código con corrección","cuerpo":"Rol: Eres ingeniero de software senior especializado en revisión de código y seguridad en [lenguaje].\nContexto: Te comparto el siguiente código para auditar: [código].\nTarea: Revisa el código para detectar bugs, ineficiencias y problemas de seguridad; explica cada hallazgo y su corrección, y devuelve la versión corregida.\nRestricciones: No introduzcas dependencias innecesarias ni cambies el comportamiento esperado salvo para corregir defectos. Justifica cada cambio con una razón concreta. Si un fragmento no tiene problemas, indícalo en vez de inventar fallos. Español neutro.\nFormato: Devuelve tres secciones: 1) Tabla de hallazgos (Tipo: bug/eficiencia/seguridad | Descripción | Gravedad | Corrección), 2) Código corregido completo en bloque de código, 3) Resumen de cambios en lista."},
  {"id":"p12","catalogo":"prompts","grupo":"Por industria","tema":"Tecnología","titulo":"Pruebas unitarias con casos límite","cuerpo":"Rol: Eres ingeniero de QA y automatización de pruebas experto en [framework].\nContexto: Necesito cobertura de tests para la siguiente función: [función].\nTarea: Escribe pruebas unitarias que cubran casos de éxito, casos límite, condiciones de error y valores nulos o vacíos.\nRestricciones: Tests independientes y deterministas, con nombres descriptivos que indiquen qué se verifica. No pruebes detalles de implementación irrelevantes. Usa aserciones claras. Español neutro en comentarios y descripciones.\nFormato: Devuelve el código de las pruebas en un bloque de código usando [framework]. Al final, añade una lista breve que enumere cada caso cubierto y por qué es relevante."},
  {"id":"p13","catalogo":"prompts","grupo":"Por industria","tema":"Tecnología","titulo":"Explicar código a un junior","cuerpo":"Rol: Eres mentor de programación con talento para enseñar conceptos complejos de forma sencilla.\nContexto: Un desarrollador junior necesita entender este código: [código].\nTarea: Explica el código paso a paso, usando analogías cotidianas para los conceptos difíciles, de modo que un junior lo comprenda sin perder rigor técnico.\nRestricciones: Evita la jerga innecesaria y, cuando la uses, defínela. No simplifiques hasta el punto de decir algo incorrecto. Mantén un tono paciente y motivador. Español neutro.\nFormato: Devuelve: 1) Resumen en una frase de qué hace el código, 2) Explicación paso a paso numerada (una idea por paso, con analogía cuando aporte), 3) Nota final con posibles errores o dudas frecuentes."},
  {"id":"p14","catalogo":"prompts","grupo":"Por industria","tema":"Tecnología","titulo":"Diseño de endpoints RESTful","cuerpo":"Rol: Eres arquitecto de APIs con experiencia en diseño de servicios RESTful.\nContexto: Estamos construyendo [tipo de app] y necesitamos definir su API siguiendo buenas prácticas REST.\nTarea: Diseña los endpoints principales indicando método HTTP, ruta, parámetros (ruta, query y cuerpo) y un ejemplo de respuesta JSON para cada uno.\nRestricciones: Usa convenciones REST coherentes (nombres de recurso en plural, verbos HTTP correctos, códigos de estado adecuados). No incluyas lógica de negocio propietaria inventada. Contempla al menos un caso de error. Español neutro en descripciones.\nFormato: Devuelve una tabla con las columnas: Método | Ruta | Descripción | Parámetros | Código de estado. Debajo de la tabla, incluye ejemplos de respuesta JSON en bloques de código para los endpoints clave."},
  {"id":"p15","catalogo":"prompts","grupo":"Por industria","tema":"Tecnología","titulo":"Documentación técnica en Markdown","cuerpo":"Rol: Eres redactor técnico especializado en documentación de código y APIs.\nContexto: Necesito documentar el siguiente código: [código].\nTarea: Genera documentación técnica en Markdown que incluya descripción general, firmas de funciones/métodos, parámetros con sus tipos, valores de retorno y un ejemplo de uso.\nRestricciones: No inventes parámetros ni comportamientos que no estén en el código: si algo es ambiguo, indícalo con una nota. Mantén un estilo claro y consistente. Español neutro.\nFormato: Devuelve un documento Markdown con secciones: Descripción, Firma(s), Parámetros (en tabla: Nombre | Tipo | Descripción), Retorno, Ejemplo de uso (bloque de código) y Notas si aplican."},
  {"id":"p16","catalogo":"prompts","grupo":"Por industria","tema":"RR. HH.","titulo":"Descripción de puesto atractiva","cuerpo":"Rol: Eres técnico de selección y employer branding con experiencia redactando ofertas de empleo que atraen talento.\nContexto: Buscamos cubrir el rol de [rol] en nuestra empresa y necesitamos una oferta clara y atractiva.\nTarea: Redacta una descripción de puesto con introducción inspiradora, responsabilidades principales, requisitos imprescindibles, requisitos deseables y beneficios.\nRestricciones: Lenguaje inclusivo y realista, sin exagerar el rol ni prometer condiciones que no se puedan cumplir. No inventes salario ni beneficios: usa placeholders. Español neutro.\nFormato: Devuelve la oferta con secciones etiquetadas: 'Sobre el puesto', 'Responsabilidades' (lista), 'Requisitos imprescindibles' (lista), 'Requisitos deseables' (lista) y 'Lo que ofrecemos' (lista)."},
  {"id":"p17","catalogo":"prompts","grupo":"Por industria","tema":"RR. HH.","titulo":"8 preguntas de entrevista STAR","cuerpo":"Rol: Eres entrevistador de RR.HH. experto en selección por competencias con método STAR (Situación, Tarea, Acción, Resultado).\nContexto: Vamos a entrevistar candidatos para el puesto de [puesto] y queremos evaluar principalmente [habilidad/competencia].\nTarea: Redacta 8 preguntas de entrevista conductual orientadas a que el candidato responda con ejemplos reales según el método STAR.\nRestricciones: Preguntas abiertas, no sugestivas y libres de sesgos discriminatorios. Cada pregunta debe apuntar a una faceta distinta de la competencia evaluada. Español neutro.\nFormato: Devuelve una lista numerada de 8 preguntas. Bajo cada pregunta, añade en una línea qué señal o comportamiento concreto se busca detectar en la respuesta."},
  {"id":"p18","catalogo":"prompts","grupo":"Por industria","tema":"RR. HH.","titulo":"Evaluación de rendimiento trimestral","cuerpo":"Rol: Eres especialista en gestión del desempeño y desarrollo de personas.\nContexto: Necesitamos una plantilla de evaluación trimestral para el puesto de [puesto], útil tanto para el manager como para la persona evaluada.\nTarea: Crea una plantilla de evaluación de rendimiento que recoja logros del trimestre, áreas de mejora y un plan de acción para el siguiente periodo.\nRestricciones: Enfoque constructivo y orientado al desarrollo, no punitivo. Incluye espacio para autoevaluación y para objetivos medibles. No inventes métricas específicas del puesto: usa placeholders. Español neutro.\nFormato: Devuelve la plantilla en secciones: 1) Datos básicos, 2) Logros del trimestre, 3) Áreas de mejora, 4) Plan de acción (tabla: Objetivo | Acción | Métrica | Fecha), 5) Comentarios de la persona evaluada."},
  {"id":"p19","catalogo":"prompts","grupo":"Por industria","tema":"RR. HH.","titulo":"Plan de onboarding 30-60-90 días","cuerpo":"Rol: Eres responsable de experiencia del empleado especializado en procesos de incorporación (onboarding).\nContexto: Vamos a incorporar a una persona en el puesto de [puesto] y queremos estructurar sus primeros 90 días.\nTarea: Diseña un plan de onboarding en tres fases (30, 60 y 90 días) con objetivos de aprendizaje, entregables y métricas de éxito para cada fase.\nRestricciones: Objetivos realistas y progresivos, coherentes con una curva de aprendizaje normal. No sobrecargues la fase de 30 días. Usa placeholders para herramientas o equipos internos. Español neutro.\nFormato: Devuelve una tabla con las columnas: Fase (30/60/90) | Objetivos de aprendizaje | Entregables | Métricas de éxito. Añade una breve nota de cierre sobre el punto de control con el manager en cada fase."},
  {"id":"p20","catalogo":"prompts","grupo":"Por industria","tema":"RR. HH.","titulo":"Correo de rescisión de contrato","cuerpo":"Rol: Eres profesional de RR.HH. con experiencia en desvinculaciones respetuosas y conformes al marco laboral.\nContexto: Debemos comunicar la rescisión de contrato de una persona por [razón], gestionando el proceso con empatía y claridad.\nTarea: Redacta un correo formal y empático que comunique la decisión e incluya los pasos siguientes: finiquito, devolución de equipo y sesión de salida.\nRestricciones: Tono humano y respetuoso, sin ambigüedades legales. No cites artículos ni importes concretos: usa placeholders y recomienda validar con asesoría legal local, ya que la normativa varía por país. Español neutro.\nFormato: Devuelve 1) línea de asunto y 2) cuerpo del correo estructurado en: comunicación de la decisión, pasos de finiquito, devolución de equipo, propuesta de sesión de salida y cierre. Añade una nota final recordando la revisión legal."},
  {"id":"p21","catalogo":"prompts","grupo":"Por industria","tema":"Finanzas y legal","titulo":"Traducir cláusula a lenguaje sencillo","cuerpo":"Rol: Eres jurista con habilidad para divulgar contenido legal en lenguaje claro (legal design).\nContexto: Necesito entender esta cláusula contractual sin perder su significado: [cláusula].\nTarea: Traduce la cláusula a lenguaje sencillo, manteniendo su validez y explicando las obligaciones y derechos que implica para cada parte.\nRestricciones: No alteres el sentido jurídico ni omitas condiciones relevantes. No sustituye asesoramiento legal profesional: indícalo. Señala cualquier término ambiguo que convenga aclarar con un abogado. Español neutro.\nFormato: Devuelve: 1) 'En palabras sencillas' (2-4 frases), 2) 'Qué obliga a cada parte' (lista por parte), 3) 'Puntos de atención' (lista de ambigüedades o riesgos) y 4) nota de descargo recomendando revisión legal."},
  {"id":"p22","catalogo":"prompts","grupo":"Por industria","tema":"Finanzas y legal","titulo":"Análisis de flujo de caja y runway","cuerpo":"Rol: Eres director financiero (CFO) con experiencia en finanzas de PyMEs y startups.\nContexto: Analiza la situación de caja con estos datos: ingresos mensuales [monto], gastos fijos mensuales [monto], costes variables mensuales [monto] y reservas actuales [monto].\nTarea: Calcula el flujo de caja neto mensual y el runway (meses de operación restantes con la caja actual), y ofrece 3 recomendaciones accionables para mejorar la posición financiera.\nRestricciones: Muestra los cálculos paso a paso y las fórmulas usadas. No inventes datos que no se hayan aportado: si falta información, indícalo. Recomendaciones prudentes y realistas, sin promesas de resultados. Español neutro.\nFormato: Devuelve: 1) Tabla resumen (Concepto | Importe), 2) Cálculo del flujo neto y del runway con fórmulas, 3) Lista numerada de 3 recomendaciones priorizadas con su impacto esperado."},
  {"id":"p23","catalogo":"prompts","grupo":"Por industria","tema":"Finanzas y legal","titulo":"Checklist de auditoría fiscal anual","cuerpo":"Rol: Eres asesor fiscal y contable con experiencia en cierres de ejercicio para PyMEs.\nContexto: Preparamos el cierre fiscal de fin de año para un negocio de tipo [modelo de negocio] y queremos revisar que todo esté en orden antes de presentar impuestos.\nTarea: Elabora un checklist de auditoría interna de preparación fiscal de fin de año, agrupado por áreas (ingresos, gastos, nóminas, activos, obligaciones fiscales y documentación).\nRestricciones: La normativa fiscal varía según el país: mantén el checklist general y recomienda validar plazos y requisitos con un asesor local. No inventes tipos impositivos ni fechas concretas. Español neutro.\nFormato: Devuelve el checklist agrupado por áreas, cada ítem como casilla verificable (- [ ] ítem). Cierra con una nota que recomiende la revisión de un profesional fiscal del país correspondiente."},
  {"id":"p24","catalogo":"prompts","grupo":"Por industria","tema":"Finanzas y legal","titulo":"Borrador de NDA mutuo","cuerpo":"Rol: Eres abogado mercantil con experiencia en redacción de acuerdos de confidencialidad.\nContexto: Necesitamos un acuerdo de confidencialidad (NDA) mutuo entre [parte A] y [parte B] para colaborar en el proyecto [proyecto].\nTarea: Redacta un borrador de NDA mutuo con las cláusulas habituales: definición de información confidencial, obligaciones de las partes, exclusiones, duración, devolución/destrucción de información, y ley aplicable.\nRestricciones: Es un borrador orientativo, no un documento legal definitivo: indícalo claramente y recomienda revisión por un abogado del país correspondiente. Usa placeholders para datos, fechas y jurisdicción. Español neutro.\nFormato: Devuelve el borrador estructurado en cláusulas numeradas con encabezados. Empieza con una nota de descargo legal y termina con bloque de firmas y espacio para fecha y lugar."},
  {"id":"p25","catalogo":"prompts","grupo":"Por industria","tema":"Finanzas y legal","titulo":"Matriz de riesgo de una inversión","cuerpo":"Rol: Eres analista de riesgos financieros y de inversión.\nContexto: Vamos a evaluar los riesgos asociados a la inversión [inversión] antes de tomar una decisión.\nTarea: Construye una matriz de riesgo que identifique los principales riesgos, su probabilidad, su impacto y una acción de mitigación para cada uno.\nRestricciones: Considera distintos tipos de riesgo (mercado, liquidez, operativo, regulatorio, etc.). No inventes datos numéricos concretos sobre la inversión: valora probabilidad e impacto en escala cualitativa (Baja/Media/Alta). Recuerda que no es asesoramiento de inversión. Español neutro.\nFormato: Devuelve una tabla con las columnas: Tipo de riesgo | Descripción | Probabilidad (Baja/Media/Alta) | Impacto (Bajo/Medio/Alto) | Mitigación. Cierra con una nota de descargo indicando que no constituye recomendación de inversión."},
  {"id":"p26","catalogo":"prompts","grupo":"Por resultados","tema":"Conversión","titulo":"Auditoría de conversión de landing","cuerpo":"Rol: Eres especialista en optimización de la tasa de conversión (CRO) con experiencia auditando landings de PyMEs.\nContexto: Analizarás el copy y la estructura de una landing a partir de este texto: [texto de la landing]. Objetivo de la página: [objetivo]. Audiencia: [audiencia].\nTarea: Identifica exactamente 3 puntos de fricción que reduzcan la conversión y, para cada uno, propón un cambio concreto y accionable (qué frase, elemento o sección modificar y cómo quedaría).\nRestricciones: Basa cada hallazgo solo en el texto aportado; no inventes métricas ni supongas datos que no estén. Prioriza por impacto potencial. Tono directo y profesional. Máximo 3 puntos de fricción.\nFormato: Tabla con columnas: Punto de fricción | Por qué frena la conversión | Cambio exacto propuesto (antes → después). Debajo, una línea con la recomendación que abordarías primero."},
  {"id":"p27","catalogo":"prompts","grupo":"Por resultados","tema":"Conversión","titulo":"Venta cruzada y upsell post-compra","cuerpo":"Rol: Eres estratega de e-commerce especializado en aumentar el valor medio del pedido mediante ofertas post-compra.\nContexto: Un cliente acaba de comprar [producto 1]. Quieres ofrecerle [producto 2] en la pantalla de confirmación con un flujo de un clic (one-click upsell). Audiencia: [audiencia].\nTarea: Diseña la estrategia de la oferta (por qué [producto 2] es relevante tras [producto 1], momento y encuadre) y redacta el copy completo de la pantalla de upsell.\nRestricciones: La oferta debe ser lógica y aportar valor real al cliente; evita presión agresiva y promesas exageradas. No inventes descuentos o cifras concretas salvo que se indiquen entre corchetes. Español neutro.\nFormato: 1) Racional de la estrategia en 3-4 líneas. 2) Copy de la pantalla: titular, subtítulo, 2-3 bullets de beneficio, botón de aceptar y enlace de rechazar. 3) Una variante alternativa del titular."},
  {"id":"p28","catalogo":"prompts","grupo":"Por resultados","tema":"Conversión","titulo":"Secuencia de carrito abandonado","cuerpo":"Rol: Eres redactor de email marketing especializado en recuperación de carritos abandonados para e-commerce.\nContexto: Nicho del negocio: [nicho]. Producto o carrito abandonado: [producto]. Buscas recuperar ventas con una secuencia de 3 correos automatizados.\nTarea: Redacta la secuencia completa. Email 1 (a la 1 hora): recordatorio amable. Email 2 (a las 24 horas): urgencia moderada + resolución de dudas frecuentes. Email 3 (a las 48 horas): incentivo final.\nRestricciones: Tono cercano y honesto, sin falsa escasez ni promesas exageradas. Cada asunto máximo 50 caracteres. Cada cuerpo entre 60 y 120 palabras. Deja el incentivo como marcador [incentivo] para que el usuario lo defina. No inventes datos del negocio.\nFormato: Para cada email indica: Momento de envío, Asunto, Texto de vista previa, Cuerpo y Llamada a la acción (texto del botón)."},
  {"id":"p29","catalogo":"prompts","grupo":"Por resultados","tema":"Conversión","titulo":"5 ideas de lead magnet","cuerpo":"Rol: Eres estratega de captación de leads (lead generation) con experiencia en embudos para servicios profesionales.\nContexto: Quieres atraer a [cliente ideal] hacia [servicio]. El objetivo es captar contactos cualificados, no solo volumen.\nTarea: Propón 5 ideas de lead magnet alineadas con la intención de compra de [cliente ideal] y con [servicio].\nRestricciones: Cada idea debe ser realista de producir para una PyME y coherente con el servicio. Evita ideas genéricas sin conexión con la venta. No prometas resultados garantizados. Español neutro.\nFormato: Tabla con columnas: Título del lead magnet | Formato (checklist, plantilla, mini-guía, calculadora, etc.) | Por qué capta leads cualificados para [servicio]. Ordena de mayor a menor potencial de cualificación."},
  {"id":"p30","catalogo":"prompts","grupo":"Por resultados","tema":"Conversión","titulo":"Testimonios con marco Antes/Después","cuerpo":"Rol: Eres redactor de copy de prueba social especializado en convertir testimonios en pruebas persuasivas y creíbles.\nContexto: Dispones de estos testimonios en bruto: [testimonios]. Quieres reescribirlos con el marco Antes/Después resaltando el beneficio cuantitativo.\nTarea: Reescribe cada testimonio estructurándolo en la situación previa del cliente, el punto de inflexión y el resultado obtenido, destacando la mejora medible.\nRestricciones: No inventes cifras ni resultados: usa solo los datos presentes en [testimonios] y, si faltan, deja un marcador como [dato a confirmar]. Mantén la voz del cliente y un tono verosímil. Máximo 60 palabras por testimonio.\nFormato: Para cada testimonio: Antes (1-2 frases) | Después (1-2 frases con el beneficio cuantitativo) | Versión final unificada lista para publicar."},
  {"id":"p31","catalogo":"prompts","grupo":"Por resultados","tema":"SEO y tráfico","titulo":"20 keywords long-tail de compra","cuerpo":"Rol: Eres especialista SEO enfocado en investigación de palabras clave con intención comercial.\nContexto: Nicho o negocio: [nicho]. Buscas keywords long-tail que reflejen intención de compra para atraer tráfico cercano a la conversión.\nTarea: Genera 20 palabras clave long-tail con intención de compra relevantes para [nicho].\nRestricciones: Todas deben ser long-tail (3+ palabras) y orientadas a decisión o compra, no informativas puras. No inventes volúmenes de búsqueda ni métricas exactas; si estimas dificultad, indícala como aproximación. Español neutro válido en España y LATAM.\nFormato: Tabla con columnas: Keyword | Intención (transaccional / comercial) | Tipo de contenido recomendado (ficha de producto, comparativa, página de servicio, etc.). 20 filas numeradas."},
  {"id":"p32","catalogo":"prompts","grupo":"Por resultados","tema":"SEO y tráfico","titulo":"Estructura de silos SEO","cuerpo":"Rol: Eres arquitecto de contenidos SEO especializado en estructuras de silos y enlazado interno.\nContexto: Productos o temas a posicionar: [productos]. Quieres una arquitectura de silo con una página pilar y contenido de soporte.\nTarea: Diseña una página pilar más 5 subpáginas de soporte y define el enlazado interno entre ellas.\nRestricciones: Cada subpágina debe cubrir un subtema diferenciado y sin canibalización con las demás. Los enlaces internos deben tener una lógica clara (pilar ↔ soporte y entre soporte cuando aporte). No inventes datos de tráfico. Español neutro.\nFormato: 1) Página pilar: título y keyword principal. 2) Tabla de las 5 subpáginas: Título | Keyword objetivo | Ángulo del contenido. 3) Esquema de enlazado interno (qué enlaza a qué y con qué texto ancla sugerido)."},
  {"id":"p33","catalogo":"prompts","grupo":"Por resultados","tema":"SEO y tráfico","titulo":"5 metatítulos y metadescripciones","cuerpo":"Rol: Eres redactor SEO especializado en snippets de resultados de búsqueda con alta tasa de clics (CTR).\nContexto: Tema o página a optimizar: [tema]. Keyword principal: [keyword]. Buscas mejorar el CTR en Google.\nTarea: Redacta 5 pares de metatítulo y metadescripción de alto CTR, integrando la keyword de forma natural e incluyendo una llamada a la acción.\nRestricciones: Metatítulo máximo 60 caracteres; metadescripción máximo 155 caracteres. No hagas keyword stuffing ni promesas exageradas. Cada variante debe usar un ángulo distinto (beneficio, urgencia, curiosidad, autoridad, prueba). Español neutro.\nFormato: Tabla con columnas: Nº | Metatítulo (con recuento de caracteres) | Metadescripción (con recuento de caracteres) | Ángulo usado."},
  {"id":"p34","catalogo":"prompts","grupo":"Por resultados","tema":"SEO y tráfico","titulo":"Email de outreach para link building","cuerpo":"Rol: Eres especialista en relaciones con editores y link building ético para SEO.\nContexto: Quieres proponer un guest post o colaboración a blogs del nicho [nicho] sobre el tema [tema]. Tu web o marca: [marca].\nTarea: Redacta un email de outreach personalizable que consiga respuesta sin sonar a spam masivo.\nRestricciones: Máximo 150 palabras. Personaliza con marcadores como [nombre del editor] y [artículo de referencia]. Aporta valor claro para el blog receptor, sin exigencias ni promesas infladas. Evita frases de plantilla evidente. Español neutro.\nFormato: 1) Línea de asunto (2 variantes). 2) Cuerpo del email con marcadores de personalización. 3) Firma de ejemplo. 4) Una nota breve de buenas prácticas para el seguimiento."},
  {"id":"p35","catalogo":"prompts","grupo":"Por resultados","tema":"SEO y tráfico","titulo":"Análisis de content gap vs competidor","cuerpo":"Rol: Eres analista de contenidos SEO especializado en detectar brechas de contenido (content gaps) frente a la competencia.\nContexto: Keyword o URL de referencia del competidor: [keyword]/[url]. Tu objetivo es superar ese contenido con una pieza más completa.\nTarea: Identifica los subtemas, preguntas o ángulos que el competidor no cubre o cubre de forma débil, y explica cómo superarlo.\nRestricciones: Trabaja solo con la información disponible en la URL o keyword indicada; no inventes datos que no puedas inferir del contexto y márcalos como [a verificar en la fuente]. Prioriza por valor para el usuario. Español neutro.\nFormato: 1) Tabla: Subtema no cubierto o débil | Por qué importa para el usuario | Cómo superarlo (formato o profundidad). 2) Esquema recomendado de la pieza mejorada (H2/H3). 3) 3 elementos diferenciadores que aporten ventaja."},
  {"id":"p36","catalogo":"prompts","grupo":"Por resultados","tema":"Productividad","titulo":"Priorizar tareas con matriz Eisenhower","cuerpo":"Rol: Eres consultor de productividad especializado en priorización con la matriz de Eisenhower.\nContexto: Lista de tareas a organizar: [tareas]. Buscas claridad sobre qué hacer primero y qué delegar o descartar.\nTarea: Clasifica cada tarea en uno de los cuatro cuadrantes (urgente e importante, importante no urgente, urgente no importante, ni urgente ni importante) y propón un orden de ejecución.\nRestricciones: Justifica brevemente cada clasificación. Si falta información para decidir urgencia o importancia, indícalo como suposición explícita en lugar de inventarla. Tono práctico. Español neutro.\nFormato: 1) Tabla con columnas: Tarea | Cuadrante | Acción recomendada (hacer, planificar, delegar, eliminar) | Justificación breve. 2) Orden de ejecución sugerido para hoy en una lista numerada."},
  {"id":"p37","catalogo":"prompts","grupo":"Por resultados","tema":"Productividad","titulo":"Resumen ejecutivo accionable","cuerpo":"Rol: Eres analista de negocio experto en sintetizar documentos extensos en resúmenes ejecutivos para la toma de decisiones.\nContexto: Documento a resumir: [documento]. La audiencia es dirección con poco tiempo que necesita decidir.\nTarea: Extrae un resumen ejecutivo de exactamente 3 puntos accionables que combinen las métricas críticas y los próximos pasos.\nRestricciones: Usa únicamente la información del documento; no añadas datos externos ni supongas cifras. Si algo no está en el documento, no lo incluyas. Cada punto debe ser concreto y orientado a la acción. Máximo 40 palabras por punto. Español neutro.\nFormato: Lista numerada de 3 puntos, cada uno con: métrica o hallazgo crítico + próximo paso recomendado. Cierra con una línea de riesgo o dato pendiente si lo hubiera."},
  {"id":"p38","catalogo":"prompts","grupo":"Por resultados","tema":"Productividad","titulo":"Automatización en Zapier o Make","cuerpo":"Rol: Eres consultor de automatización de procesos con experiencia en Zapier y Make para PyMEs.\nContexto: Quieres automatizar un flujo: cuando ocurra [acción inicial], se debe ejecutar [acción secundaria]. Herramientas implicadas: [herramientas].\nTarea: Explica paso a paso cómo montar esta automatización, indicando disparador (trigger), acción y configuraciones clave.\nRestricciones: Explica en lenguaje claro para alguien sin perfil técnico. No inventes nombres exactos de módulos si dependen de la versión; descríbelos de forma genérica y señala dónde confirmar. Incluye una comprobación de que funciona. Español neutro.\nFormato: 1) Resumen del flujo en una frase. 2) Pasos numerados (disparador → filtros → acción → prueba). 3) Campos o datos a mapear. 4) Sugerencia de manejo de errores o casos límite."},
  {"id":"p39","catalogo":"prompts","grupo":"Por resultados","tema":"Productividad","titulo":"5 plantillas de atención al cliente","cuerpo":"Rol: Eres especialista en atención al cliente y diseño de respuestas plantilla (macros de soporte).\nContexto: Negocio: [negocio]. Quieres respuestas reutilizables para las dudas más frecuentes de tus clientes.\nTarea: Redacta 5 respuestas plantilla para las consultas más comunes de [negocio], cada una con marcadores de personalización.\nRestricciones: Tono empático, claro y honesto; sin prometer lo que el negocio no puede cumplir. Incluye marcadores como [nombre del cliente] y [detalle del pedido]. Cada respuesta máximo 90 palabras. No inventes políticas concretas: deja marcadores para ellas. Español neutro.\nFormato: Para cada plantilla: Título de la consulta | Respuesta con marcadores | Nota breve de cuándo usarla. 5 plantillas numeradas."},
  {"id":"p40","catalogo":"prompts","grupo":"Por resultados","tema":"Productividad","titulo":"Estructura de daily stand-up","cuerpo":"Rol: Eres facilitador ágil (agile) con experiencia dirigiendo reuniones diarias eficaces.\nContexto: Equipo de 6 personas de perfil [dev/marketing]. Quieres un stand-up diario de 15 minutos que no se alargue.\nTarea: Diseña la estructura minuto a minuto del stand-up y define reglas anti-divagación que lo mantengan enfocado.\nRestricciones: El total no debe superar 15 minutos. Reparte el tiempo de forma realista para 6 personas. Las reglas deben ser aplicables y respetuosas. No inventes herramientas concretas salvo que se indiquen. Español neutro.\nFormato: 1) Agenda con reparto de tiempos (bloques en minutos). 2) Las 3 preguntas guía para cada persona. 3) Lista de reglas anti-divagación (qué hacer cuando una conversación se alarga o se sale de tema). 4) Rol del facilitador."},
  {"id":"p41","catalogo":"prompts","grupo":"Por resultados","tema":"Retención","titulo":"Email de NPS con respuestas tipo","cuerpo":"Rol: Eres especialista en experiencia de cliente y programas de NPS (Net Promoter Score).\nContexto: Servicio: [servicio]. Quieres medir la satisfacción con una encuesta NPS y actuar según la puntuación.\nTarea: Redacta el email de solicitud de NPS y 2 plantillas de respuesta: una para promotores (9-10) invitándolos a dejar una reseña, y otra para detractores (1-6) pidiéndoles feedback para mejorar.\nRestricciones: Tono cercano y honesto; no presiones ni ofrezcas incentivos por reseñas positivas. Incluye marcadores como [nombre del cliente] y [enlace de reseña]. Email de solicitud máximo 80 palabras; cada plantilla máximo 90 palabras. Español neutro.\nFormato: 1) Email de solicitud (asunto + cuerpo con la pregunta y escala 0-10). 2) Plantilla promotores (9-10). 3) Plantilla detractores (1-6). Menciona brevemente qué hacer con los pasivos (7-8)."},
  {"id":"p42","catalogo":"prompts","grupo":"Por resultados","tema":"Retención","titulo":"Onboarding de trial en 4 emails","cuerpo":"Rol: Eres estratega de activación (onboarding) para productos SaaS con enfoque en el momento de valor.\nContexto: Software: [software]. Prueba gratuita de 14 días. Quieres guiar al usuario hasta su momento ajá (aha moment): [momento ajá].\nTarea: Diseña una estrategia de 4 emails de bienvenida repartidos en los 14 días de trial que lleven al usuario a experimentar el valor del producto.\nRestricciones: Cada email debe tener un único objetivo claro y una sola llamada a la acción. Tono útil, no comercial agresivo. No inventes funciones del software: usa marcadores como [función clave]. Español neutro.\nFormato: Tabla con columnas: Nº email | Día de envío | Objetivo | Asunto | Idea central del cuerpo | Llamada a la acción. Debajo, redacta completo el email 1 como ejemplo."},
  {"id":"p43","catalogo":"prompts","grupo":"Por resultados","tema":"Retención","titulo":"Email de reactivación de clientes","cuerpo":"Rol: Eres redactor de email marketing especializado en reactivación de clientes inactivos (win-back).\nContexto: Tienda: [tienda]. Segmento: clientes que no compran desde hace 6 meses. Quieres recuperarlos con un beneficio de valor real.\nTarea: Redacta un email de reactivación que reconozca la ausencia, recuerde el valor de la tienda y ofrezca un beneficio concreto para volver.\nRestricciones: Tono cálido y honesto, sin culpabilizar al cliente ni usar falsa urgencia. Deja el beneficio como marcador [beneficio] para que el usuario lo defina. Máximo 120 palabras. Incluye marcadores de personalización. Español neutro.\nFormato: 1) Asunto (2 variantes). 2) Texto de vista previa. 3) Cuerpo del email. 4) Texto del botón de llamada a la acción."},
  {"id":"p44","catalogo":"prompts","grupo":"Por resultados","tema":"Retención","titulo":"Programa de fidelización","cuerpo":"Rol: Eres consultor de fidelización y retención de clientes con experiencia diseñando programas de puntos y niveles.\nContexto: Negocio: [negocio]. Tipo de cliente: [audiencia]. Quieres un programa de fidelización sencillo de gestionar y atractivo.\nTarea: Diseña la estructura del programa: sistema de acumulación de puntos, niveles y recompensas.\nRestricciones: El programa debe ser sostenible para el margen del negocio y fácil de entender para el cliente. No inventes cifras de canje: preséntalas como propuesta con marcadores editables. Evita promesas de recompensas irreales. Español neutro.\nFormato: 1) Cómo se ganan puntos (acciones y valor propuesto). 2) Tabla de niveles: Nivel | Requisito | Beneficios. 3) Catálogo de recompensas de ejemplo. 4) Recomendaciones para comunicar y lanzar el programa."},
  {"id":"p45","catalogo":"prompts","grupo":"Por resultados","tema":"Retención","titulo":"Protocolo de quejas en redes sociales","cuerpo":"Rol: Eres especialista en gestión de comunidad y reputación en redes sociales (community y crisis management).\nContexto: Recibes una queja pública en redes sobre [problema]. Quieres responder bien en público y resolver en privado.\nTarea: Define un protocolo de 3 pasos para gestionar la queja y redacta una plantilla de respuesta pública y una plantilla de respuesta privada.\nRestricciones: Prioriza empatía, transparencia y rapidez; nunca discutir en público ni negar sin verificar. No inventes la causa del problema: usa marcadores como [detalle a confirmar]. Respuesta pública breve (máximo 40 palabras). Español neutro.\nFormato: 1) Protocolo en 3 pasos (qué hacer y en qué orden). 2) Plantilla de respuesta pública con marcadores. 3) Plantilla de respuesta privada con marcadores. 4) Nota sobre qué evitar."},
  {"id":"p46","catalogo":"prompts","grupo":"Por resultados","tema":"Captación de leads","titulo":"Guion minuto a minuto de webinar","cuerpo":"Rol: Eres estratega de webinars enfocados en captar leads para ofertas de ticket alto (high-ticket).\nContexto: Webinar de 45 minutos para captar leads de un programa de precio [precio]. Audiencia: [audiencia]. Tema: [tema].\nTarea: Diseña la estructura minuto a minuto del webinar que mantenga la atención y prepare la conversión sin resultar agresivo.\nRestricciones: El total debe encajar en 45 minutos. Equilibra contenido de valor y oferta; evita promesas exageradas o falsa escasez. Deja marcadores para datos concretos. Incluye momento de preguntas. Español neutro.\nFormato: Tabla con columnas: Tramo (minutos) | Sección | Objetivo | Qué se dice o muestra. Cierra con la estructura recomendada de la llamada a la acción final y una respuesta breve a 2 objeciones frecuentes."},
  {"id":"p47","catalogo":"prompts","grupo":"Por resultados","tema":"Captación de leads","titulo":"5 preguntas de calificación BANT","cuerpo":"Rol: Eres especialista en ventas B2B y calificación de leads con el marco BANT (presupuesto, autoridad, necesidad, plazo).\nContexto: Servicio B2B: [servicio]. Quieres calificar leads mediante un formulario interactivo antes de agendar una llamada.\nTarea: Redacta 5 preguntas de calificación que cubran los cuatro criterios BANT y ayuden a priorizar los mejores leads.\nRestricciones: Las preguntas deben ser claras, no invasivas y responderse fácilmente en un formulario. Evita jerga interna. Ofrece opciones de respuesta donde aporte (por ejemplo, rangos de presupuesto con marcadores). No inventes precios. Español neutro.\nFormato: Tabla con columnas: Nº | Pregunta | Criterio BANT que evalúa | Opciones de respuesta sugeridas o tipo de campo. Debajo, una nota de cómo interpretar las respuestas para priorizar."},
  {"id":"p48","catalogo":"prompts","grupo":"Por resultados","tema":"Captación de leads","titulo":"Quiz de autoevaluación para leads","cuerpo":"Rol: Eres diseñador de contenidos interactivos especializado en quizzes de captación de leads.\nContexto: Sector objetivo: [sector]. Título propuesto del quiz: [título]. Quieres captar leads con una autoevaluación que aporte valor y segmente.\nTarea: Diseña un quiz de 5 preguntas de opción múltiple y 3 perfiles de resultado que orienten al usuario y preparen el siguiente paso comercial.\nRestricciones: Preguntas breves y neutrales, sin sesgar hacia una única respuesta. Cada perfil de resultado debe ser honesto y accionable, sin descalificar al usuario. No inventes datos del sector. Español neutro.\nFormato: 1) Las 5 preguntas, cada una con 3-4 opciones y su valor o puntuación. 2) Lógica de puntuación para asignar perfil. 3) Los 3 perfiles de resultado: nombre, descripción y recomendación o siguiente paso."},
  {"id":"p49","catalogo":"prompts","grupo":"Por resultados","tema":"Captación de leads","titulo":"Copy de LinkedIn Ads para lead gen","cuerpo":"Rol: Eres redactor publicitario especializado en campañas de generación de leads en LinkedIn Ads.\nContexto: Ofreces la descarga de la guía [recurso] mediante un formulario nativo de LinkedIn (lead gen form). Público objetivo por puesto: [puesto]. Sector: [sector].\nTarea: Redacta el copy del anuncio para captar descargas cualificadas, alineado con el puesto y el dolor de [puesto].\nRestricciones: Respeta los límites de LinkedIn: texto introductorio conciso (idealmente bajo 150 caracteres antes del corte) y titular breve. Tono profesional y honesto, sin promesas exageradas. Incluye una llamada a la acción coherente con el formulario nativo. Español neutro.\nFormato: 1) Texto introductorio (2 variantes). 2) Titular del anuncio (2 variantes, máximo 70 caracteres). 3) Texto del botón de CTA sugerido. 4) Nota breve de segmentación recomendada por puesto o sector."},
  {"id":"p50","catalogo":"prompts","grupo":"Por resultados","tema":"Captación de leads","titulo":"Propuesta de co-marketing","cuerpo":"Rol: Eres estratega de alianzas y co-marketing entre marcas complementarias.\nContexto: Marca de referencia: [marca]. Audiencia: [audiencia]. Buscas socios no competidores que compartan público para colaboraciones de beneficio mutuo.\nTarea: Identifica 3 nichos o tipos de marca complementarios a [marca] y propón una acción concreta de colaboración cruzada para cada uno.\nRestricciones: Los nichos deben ser complementarios y no competidores directos, con audiencia solapada realista. Cada propuesta debe beneficiar a ambas partes y ser viable para una PyME. No inventes nombres de empresas reales concretas; describe el tipo de socio. Español neutro.\nFormato: Tabla con columnas: Nicho complementario | Por qué encaja con [marca] | Propuesta de colaboración cruzada | Beneficio para cada parte. Debajo, un ejemplo de mensaje de primer contacto para proponer la alianza."},
  {"id":"p51","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Análisis de datos","titulo":"Matriz DAFO en tabla","cuerpo":"Rol: Eres consultor de estrategia empresarial con experiencia en análisis competitivo para PyMEs.\nContexto: Necesito evaluar la posición estratégica de un negocio antes de tomar decisiones de crecimiento. Descripción del negocio: [negocio].\nTarea: Elabora una matriz DAFO (Debilidades, Amenazas, Fortalezas, Oportunidades) a partir de la descripción proporcionada, con entradas específicas y accionables, no genéricas.\nRestricciones: Incluye entre 3 y 5 puntos por cuadrante. Distingue con claridad factores internos (fortalezas, debilidades) de externos (oportunidades, amenazas). Señala explícitamente cuando falte información y qué dato haría falta para completar el análisis. No inventes cifras.\nFormato: Una tabla de dos columnas por dos filas con los cuatro cuadrantes. Debajo, un párrafo breve (máximo 4 líneas) con la conclusión estratégica principal."},
  {"id":"p52","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Análisis de datos","titulo":"Extraer métricas a JSON","cuerpo":"Rol: Eres analista financiero especializado en normalizar datos de reportes para su procesamiento.\nContexto: Tengo un reporte con información financiera dispersa y necesito estructurarla para cargarla en una herramienta. Reporte: [reporte].\nTarea: Extrae del reporte los siguientes indicadores y devuélvelos en JSON: ingresos totales, CAC (coste de adquisición de cliente), margen bruto y tasa de churn.\nRestricciones: No inventes valores. Si un dato no aparece o es ambiguo, asígnale null e indícalo en un campo de notas. Conserva la moneda y la unidad originales (porcentaje, valor absoluto). Incluye el periodo del reporte si está disponible.\nFormato: Un único objeto JSON válido con las claves: periodo, moneda, ingresos_totales, cac, margen_bruto_pct, churn_pct y notas (array de strings). Sin texto fuera del bloque de código."},
  {"id":"p53","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Análisis de datos","titulo":"Análisis de sentimiento de opiniones","cuerpo":"Rol: Eres analista de experiencia de cliente (CX) con práctica en clasificación de feedback.\nContexto: He recopilado opiniones de clientes y quiero entender su percepción y detectar patrones. Opiniones: [opiniones].\nTarea: Clasifica cada opinión por sentimiento e identifica el problema o beneficio principal que menciona.\nRestricciones: Usa solo tres etiquetas de sentimiento: positivo, neutro o negativo. Basa la clasificación en el texto, sin suponer intenciones no expresadas. Si una opinión es ambigua, márcala como neutro y explica por qué. Resume el problema o beneficio en una frase corta.\nFormato: Una tabla con tres columnas: Comentario (resumido si es largo), Sentimiento, Problema o beneficio principal. Al final, una línea con el recuento por sentimiento."},
  {"id":"p54","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Análisis de datos","titulo":"Tabla comparativa vs competidores","cuerpo":"Rol: Eres analista de producto especializado en benchmarking competitivo.\nContexto: Quiero situar mi producto frente a dos competidores para clarificar mi propuesta de valor. Competidores: [competidor A] y [competidor B].\nTarea: Elabora una tabla comparativa entre mi producto y ambos competidores según: precio, funciones, facilidad de uso y soporte.\nRestricciones: Si no dispones de datos verificables de un competidor, indícalo como \"por confirmar\" en lugar de inventar. No exageres las ventajas de mi producto; mantén una comparación honesta. Señala dónde soy más débil, no solo dónde soy fuerte.\nFormato: Una tabla con la primera columna de criterios y una columna por cada producto. Debajo, tres viñetas: mi principal ventaja, mi principal desventaja y el hueco de mercado que sugiere la comparación."},
  {"id":"p55","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Análisis de datos","titulo":"Traducción técnica con glosario","cuerpo":"Rol: Eres traductor técnico profesional especializado en el sector [industria].\nContexto: Necesito traducir un texto conservando la precisión terminológica del sector. Texto: [texto]. Idioma de origen: [idioma origen]. Idioma de destino: [idioma destino].\nTarea: Traduce el texto de [idioma origen] a [idioma destino] y elabora un glosario con los términos técnicos clave.\nRestricciones: Prioriza la fidelidad del significado sobre la traducción literal. Mantén coherencia terminológica en todo el texto. Conserva sin traducir nombres propios, marcas y siglas de uso estándar en el sector. Si un término admite varias traducciones, elige la más aceptada y anótalo en el glosario.\nFormato: Primero la traducción completa. Después, una tabla de glosario con tres columnas: Término original, Traducción, Nota o contexto de uso."},
  {"id":"p56","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Creatividad","titulo":"SCAMPER aplicado a producto","cuerpo":"Rol: Eres facilitador de innovación con experiencia en metodologías de ideación estructurada.\nContexto: Quiero generar mejoras y variaciones sobre un producto existente usando un marco sistemático. Producto: [producto].\nTarea: Aplica el método SCAMPER y propón al menos una idea concreta para cada una de sus siete letras: Sustituir, Combinar, Adaptar, Modificar, Poner en otros usos, Eliminar y Reordenar.\nRestricciones: Cada idea debe ser específica y aplicable al producto, no un enunciado abstracto. Evita repetir la misma idea en distintas letras. Prioriza ideas realistas frente a las meramente llamativas.\nFormato: Siete secciones encabezadas por cada letra de SCAMPER. En cada una: la idea en una frase y una línea sobre el beneficio esperado. Al final, señala las 2 ideas con mejor relación impacto-esfuerzo."},
  {"id":"p57","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Creatividad","titulo":"Nombres de marca para producto","cuerpo":"Rol: Eres especialista en naming y branding para mercados hispanohablantes.\nContexto: Estoy lanzando un producto y busco opciones de nombre alineadas con mi público. Producto: [producto]. Público objetivo: [público].\nTarea: Propón 15 nombres de marca modernos, evocativos y con sonoridad hispana adecuada al público.\nRestricciones: Evita nombres difíciles de pronunciar o escribir en español. No propongas marcas registradas conocidas ni imitaciones evidentes. Prioriza nombres cortos y memorables. Recuerda al usuario que debe verificar disponibilidad de dominio y registro de marca antes de decidir.\nFormato: Una lista numerada del 1 al 15. Cada entrada: el nombre en negrita y una frase breve que explique su significado o asociación. Al final, tus 3 favoritos con una razón."},
  {"id":"p58","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Creatividad","titulo":"Títulos contraintuitivos con argumento","cuerpo":"Rol: Eres editor de contenidos especializado en titulares que captan atención sin engañar.\nContexto: Quiero titulares que despierten curiosidad sobre un tema manteniendo la honestidad con el lector. Tema: [tema].\nTarea: Escribe 5 títulos contraintuitivos (clickbait ético) y, para cada uno, el argumento real que lo sostiene.\nRestricciones: El título debe poder cumplirse con el contenido; nada de promesas que no se puedan defender. Evita el sensacionalismo vacío y las mayúsculas excesivas. Cada argumento debe justificar de forma verosímil por qué la afirmación es cierta.\nFormato: Una lista numerada del 1 al 5. Por cada punto: \"Título:\" seguido del titular y, en la línea siguiente, \"Argumento:\" con 1 o 2 frases que lo respalden."},
  {"id":"p59","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Creatividad","titulo":"Hibridación de modelos de negocio","cuerpo":"Rol: Eres estratega de modelos de negocio con experiencia en innovación entre sectores.\nContexto: Quiero explorar oportunidades trasladando un modelo de negocio probado a un sector distinto. Empresa de referencia: [empresa conocida]. Sector objetivo: [X].\nTarea: Combina el modelo de negocio de [empresa conocida] con el sector [X] y propón 3 ideas de negocio viables.\nRestricciones: Cada idea debe explicar qué elemento del modelo original se traslada y por qué encaja en el nuevo sector. Sé realista sobre barreras de entrada y requisitos. No prometas rentabilidad garantizada; describe supuestos y riesgos principales.\nFormato: Tres bloques numerados. Cada uno con: Nombre tentativo, Qué se traslada del modelo original, Propuesta de valor, Cliente objetivo, y Principal riesgo o supuesto a validar."},
  {"id":"p60","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Creatividad","titulo":"Hooks de apertura para vídeo","cuerpo":"Rol: Eres guionista de contenido en vídeo corto especializado en retención de audiencia.\nContexto: Necesito ganchos de apertura potentes para el primer instante de un vídeo. Tema: [tema].\nTarea: Escribe 10 hooks de apertura de menos de 5 segundos (frases breves para decir o mostrar al inicio), usando palancas de curiosidad, FOMO y desmontaje de mitos.\nRestricciones: Cada hook debe ser una frase corta y hablada con naturalidad. Evita promesas exageradas o afirmaciones que el vídeo no pueda cumplir. Reparte las palancas: no uses siempre la misma. Español neutro, sin modismos locales.\nFormato: Una lista numerada del 1 al 10. Cada línea: el hook entre comillas y, entre paréntesis, la palanca usada (curiosidad, FOMO o mito)."},
  {"id":"p61","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Simulación de roles","titulo":"Simulación de pitch ante VC","cuerpo":"Rol: Eres un inversor de capital riesgo (VC) experimentado que evalúa startups en fase temprana.\nContexto: Me preparo para presentar mi startup ante inversores y quiero anticipar las preguntas más incómodas. Nicho de la startup: [nicho].\nTarea: Formula 3 preguntas difíciles centradas en tracción, barreras de entrada y rentabilidad, y actúa como el inversor durante el intercambio.\nRestricciones: Las preguntas deben ser específicas del nicho, no genéricas. Mantén un tono exigente pero profesional. No respondas por mí: espera mi respuesta a cada pregunta antes de continuar y evalúa su solidez señalando huecos.\nFormato: Presenta las 3 preguntas numeradas de una en una. Tras cada respuesta mía, ofrece una valoración breve (qué convence y qué falta) antes de pasar a la siguiente."},
  {"id":"p62","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Simulación de roles","titulo":"Feedback crítico de mentor","cuerpo":"Rol: Eres un mentor perfeccionista con amplia trayectoria en producto y diseño.\nContexto: Quiero un análisis honesto y exigente de una idea antes de invertir tiempo en ella. Idea: [idea].\nTarea: Ofrece feedback crítico y detallado sobre la idea desde la óptica de producto y diseño, identificando debilidades que otros pasarían por alto.\nRestricciones: Sé directo pero constructivo: cada crítica debe ir acompañada de una vía de mejora concreta. No adules ni suavices para agradar. Prioriza los problemas por impacto. Distingue lo que es opinión de lo que es un principio establecido.\nFormato: Tres secciones: \"Lo que funciona\" (breve), \"Problemas por resolver\" (lista priorizada con crítica + sugerencia) y \"La pregunta que definiría el proyecto\" (una sola pregunta clave)."},
  {"id":"p63","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Simulación de roles","titulo":"Entrevista de trabajo interactiva","cuerpo":"Rol: Eres un entrevistador senior de selección de personal para el puesto de [puesto].\nContexto: Quiero practicar una entrevista de trabajo realista y mejorar mis respuestas. Puesto: [puesto].\nTarea: Conduce una entrevista simulada, formulando una pregunta cada vez y evaluando mi respuesta antes de continuar.\nRestricciones: Haz una sola pregunta por turno y espera mi respuesta; no adelantes varias. Combina preguntas técnicas, de comportamiento y de motivación adecuadas al puesto. Tras cada respuesta, da feedback breve y una sugerencia de mejora. Mantén un tono profesional y realista.\nFormato: Por turno: \"Pregunta [n]:\" con la pregunta. Tras mi respuesta: \"Valoración:\" con 2 o 3 líneas de feedback y luego la siguiente pregunta. Al terminar (unas 6-8 preguntas), un resumen final con fortalezas y áreas de mejora."},
  {"id":"p64","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Simulación de roles","titulo":"Abogado del diablo sobre el plan","cuerpo":"Rol: Eres un analista de riesgos que actúa deliberadamente como abogado del diablo.\nContexto: Antes de ejecutar un plan quiero exponer sus puntos débiles ocultos. Proyecto: [proyecto].\nTarea: Cuestiona el plan de forma rigurosa e identifica puntos únicos de fallo, asunciones erróneas y riesgos ocultos.\nRestricciones: No busques agradar: tu función es encontrar lo que puede salir mal. Cada objeción debe ser plausible y explicada, no alarmismo sin fundamento. Distingue riesgos de alta probabilidad de los de bajo impacto. Para cada riesgo relevante, sugiere una forma de mitigarlo o validarlo.\nFormato: Tres secciones: \"Puntos únicos de fallo\", \"Asunciones que podrían ser falsas\" y \"Riesgos ocultos\". Cada punto con una línea de riesgo y otra de mitigación. Cierra con el riesgo que consideras más crítico."},
  {"id":"p65","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Simulación de roles","titulo":"Simulación de cliente enfadado","cuerpo":"Rol: Eres un cliente molesto que ha recibido un producto equivocado y evalúa la atención que recibe.\nContexto: Quiero entrenar mi capacidad de resolver conflictos con clientes difíciles bajo presión.\nTarea: Interpreta a ese cliente enfadado durante una conversación de atención y evalúa mi empatía y mi eficacia para resolver el problema.\nRestricciones: Mantén el enfado de forma realista pero sin insultos ni lenguaje ofensivo. Reacciona de forma coherente: si muestro empatía y ofrezco soluciones útiles, baja la tensión; si respondo mal, mantente firme. No resuelvas el conflicto por mí. Espera mi respuesta en cada turno.\nFormato: Diálogo por turnos. Interpreta al cliente en primera persona. Al finalizar la conversación, sal del personaje y ofrece una evaluación con puntuación de empatía y de eficacia (de 1 a 5) y dos recomendaciones concretas."},
  {"id":"p66","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Copywriting","titulo":"Publicación de LinkedIn con PAS","cuerpo":"Rol: Eres copywriter B2B especializado en contenido para LinkedIn.\nContexto: Quiero publicar un post que conecte con una audiencia profesional y presente una solución. Dolor a abordar: [dolor]. Solución a presentar: [solución].\nTarea: Redacta una publicación de LinkedIn de unas 200 palabras con la fórmula PAS (Problema, Agitación, Solución).\nRestricciones: Empieza con un gancho fuerte en la primera línea. Agita el problema con realismo, sin dramatizar en exceso ni prometer resultados garantizados. Presenta la solución de forma honesta. Tono profesional y cercano, español neutro. Incluye una llamada a la acción suave al final.\nFormato: Texto listo para publicar, con frases y párrafos cortos y saltos de línea para facilitar la lectura en móvil. Añade al final 3 a 5 hashtags relevantes."},
  {"id":"p67","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Copywriting","titulo":"Página de ventas con AIDA","cuerpo":"Rol: Eres copywriter de respuesta directa especializado en páginas de venta.\nContexto: Necesito una página de ventas persuasiva y honesta para un producto. Producto: [producto]. Función principal: [función].\nTarea: Escribe una página de ventas con la estructura AIDA (Atención, Interés, Deseo, Acción), con titulares diferenciados por fase del embudo.\nRestricciones: Enfoca el mensaje en beneficios reales para el cliente, no solo en características. Evita promesas exageradas o garantías que no se puedan cumplir; usa pruebas o ejemplos cuando aporten credibilidad. Español neutro. Incluye un solo objetivo de conversión claro.\nFormato: Secciones etiquetadas Atención, Interés, Deseo y Acción, cada una con su titular y su cuerpo. Incluye 2 variantes de titular principal y una llamada a la acción final destacada."},
  {"id":"p68","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Copywriting","titulo":"Guion Nuestra Historia (Viaje del Héroe)","cuerpo":"Rol: Eres narrador de marca (brand storyteller) especializado en storytelling corporativo.\nContexto: Quiero una sección \"Nuestra Historia\" que conecte emocionalmente con el cliente. Industria: [industria].\nTarea: Escribe el guion de \"Nuestra Historia\" aplicando la estructura del Viaje del Héroe, situando al cliente como héroe y a la marca como guía.\nRestricciones: El protagonista debe ser el cliente, no la empresa; la marca cumple el papel de mentor. Mantén el relato creíble y evita heroísmos exagerados o datos inventados; deja como placeholders los hitos concretos. Tono humano y cercano, español neutro.\nFormato: Un texto narrativo dividido en fases visibles: Mundo ordinario, Llamada o reto, El guía aparece, La transformación y El nuevo presente. Extensión aproximada de 300 a 400 palabras."},
  {"id":"p69","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Copywriting","titulo":"Reescribir texto académico accesible","cuerpo":"Rol: Eres editor de divulgación experto en acercar textos complejos a públicos amplios.\nContexto: Tengo un texto académico denso y quiero adaptarlo a un público joven profesional. Texto: [texto].\nTarea: Reescribe el texto con un tono fresco y accesible para profesionales de 20 a 30 años, sin perder el rigor de las ideas.\nRestricciones: Conserva el significado y los datos originales; no simplifiques hasta distorsionar. Sustituye la jerga técnica por lenguaje claro, explicando el término la primera vez si es imprescindible. Evita el lenguaje forzadamente juvenil o los modismos. Frases cortas y voz activa.\nFormato: El texto reescrito. Debajo, una nota breve de 2 o 3 líneas que resuma los principales cambios de estilo aplicados."},
  {"id":"p70","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Copywriting","titulo":"Convertir post en hilo de tuits","cuerpo":"Rol: Eres estratega de contenido en redes sociales especializado en formato hilo.\nContexto: Tengo un artículo largo que quiero difundir como hilo en redes. Texto: [texto].\nTarea: Conviértelo en un hilo de 6 tuits: un tuit de gancho, cuatro con las ideas clave y un tuit final con llamada a la acción.\nRestricciones: Cada tuit debe respetar un máximo de 280 caracteres y sostenerse por sí mismo. Mantén fidelidad al contenido original; no añadas afirmaciones no presentes en el texto. Encadena los tuits con continuidad lógica. Español neutro, sin promesas exageradas.\nFormato: Seis tuits numerados (1/6 a 6/6). Indica entre paréntesis el recuento de caracteres de cada uno. El tuit 1 es el gancho y el 6 la llamada a la acción."},
  {"id":"p71","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Negociación","titulo":"Guion para negociar aumento salarial","cuerpo":"Rol: Eres coach de carrera especializado en negociación salarial.\nContexto: Quiero preparar una conversación para pedir un aumento con argumentos sólidos. Puesto: [puesto]. Logros: [lista]. Media de mercado: [monto].\nTarea: Diseña una estrategia de negociación y redacta un guion de apertura para solicitar el aumento.\nRestricciones: Basa los argumentos en los logros aportados y en la referencia de mercado, sin exigencias ni ultimátums. Anticipa 2 posibles objeciones y cómo responderlas. Mantén un tono profesional y colaborativo. Recuerda que el resultado depende de factores del empleador; no garantices el aumento.\nFormato: Dos partes. \"Estrategia\": viñetas con enfoque, cifra objetivo y margen de negociación. \"Guion de apertura\": un párrafo listo para decir, seguido de las 2 objeciones previstas con su respuesta sugerida."},
  {"id":"p72","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Negociación","titulo":"Marco de resolución entre socios","cuerpo":"Rol: Eres mediador de conflictos con experiencia en sociedades y equipos fundadores.\nContexto: Existe tensión entre dos socios con roles distintos: uno lleva la operativa y otro la estrategia.\nTarea: Propón un marco de resolución de 4 puntos para abordar y encauzar el conflicto de forma equilibrada.\nRestricciones: Mantén neutralidad: no favorezcas a ningún socio. Céntrate en intereses y responsabilidades, no en culpables. Cada punto debe ser accionable y aplicable a una conversación real. Reconoce cuándo conviene acudir a un acuerdo formal o asesoría externa.\nFormato: Cuatro puntos numerados, cada uno con un título breve y 2 o 3 líneas de explicación con un paso concreto. Cierra con una pregunta de alineación que ambos socios deberían responder juntos."},
  {"id":"p73","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Negociación","titulo":"Email para negociar con proveedor","cuerpo":"Rol: Eres responsable de compras (procurement) con experiencia en negociación con proveedores.\nContexto: Quiero renegociar el precio con un proveedor ofreciendo permanencia a cambio de descuento. Servicio: [servicio].\nTarea: Redacta un email para negociar una reducción del 15% en el precio a cambio de un compromiso de permanencia de 2 años.\nRestricciones: Mantén un tono cordial y orientado a la relación a largo plazo, no impositivo. Justifica la petición con valor mutuo (estabilidad para el proveedor a cambio de mejor precio). Deja margen para contraoferta. Evita amenazas de cambio de proveedor como primer recurso. Español neutro.\nFormato: Un email completo con asunto, saludo, cuerpo estructurado (contexto, propuesta, beneficio para ambas partes, cierre) y despedida. Incluye un espacio con placeholders para datos concretos."},
  {"id":"p74","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Negociación","titulo":"Respuesta pública a reseña de 1 estrella","cuerpo":"Rol: Eres gestor de reputación online (community manager) con experiencia en atención pública.\nContexto: He recibido una reseña negativa de 1 estrella y necesito responder públicamente sin perjudicar mi imagen. Tipo de negocio: [tipo].\nTarea: Redacta una respuesta pública educada a la reseña que muestre disposición a resolver, sin asumir culpa legal.\nRestricciones: Agradece el comentario y muestra empatía sin admitir responsabilidad ni reconocer hechos que puedan tener implicaciones legales. No reveles datos privados del cliente. Invita a continuar la conversación por un canal privado. Mantén la calma y el tono profesional aunque la reseña sea injusta.\nFormato: Una respuesta breve de 4 a 6 líneas lista para publicar. Debajo, una nota interna de 2 líneas explicando la estrategia elegida."},
  {"id":"p75","catalogo":"prompts","grupo":"Mejores casos de uso","tema":"Negociación","titulo":"Email por trabajo fuera de alcance","cuerpo":"Rol: Eres consultor freelance con experiencia en gestión de clientes y alcance de proyectos.\nContexto: Un cliente solicita tareas que exceden lo acordado y necesito responder protegiendo la relación y el proyecto. Proyecto: [proyecto].\nTarea: Redacta un email firme pero educado que indique que la petición queda fuera del alcance acordado y que requeriría un presupuesto adicional.\nRestricciones: Reconoce el valor de la solicitud sin acceder gratis a ella. Referencia el alcance original con claridad. Ofrece una vía de continuidad (presupuesto o ampliación) en lugar de un simple no. Mantén un tono profesional y colaborativo, evitando sonar defensivo. Español neutro.\nFormato: Un email con asunto, saludo, cuerpo (reconocimiento, referencia al alcance, propuesta de presupuesto adicional, cierre abierto) y despedida. Deja placeholders para el detalle de la tarea y la cifra estimada."},
  {"id":"p76","catalogo":"prompts","grupo":"Por objetivos","tema":"Reducción de costes","titulo":"Detectar desperdicios con Lean Six Sigma","cuerpo":"Rol: Eres consultor en mejora de procesos con certificación Lean Six Sigma y experiencia en operaciones de atención al cliente.\nContexto: Trabajo en [empresa/sector] y quiero reducir costes sin dañar la experiencia del cliente. El flujo actual es: [describe el flujo de atención al cliente paso a paso].\nTarea: Identifica exactamente 3 ineficiencias o desperdicios (muda) en ese flujo, clasificándolos según las categorías Lean (espera, transporte, sobreprocesamiento, defectos, etc.) y explica cómo cada uno genera coste.\nRestricciones: Basa el análisis solo en la información que te doy; si falta un dato clave, indícalo en lugar de suponerlo. No prometas ahorros concretos sin datos que los respalden. Evita tecnicismos sin explicar.\nFormato: Tabla con columnas: Desperdicio | Tipo Lean | Impacto en coste | Acción de mejora sugerida | Esfuerzo estimado (bajo/medio/alto). Cierra con una recomendación de por dónde empezar."},
  {"id":"p77","catalogo":"prompts","grupo":"Por objetivos","tema":"Reducción de costes","titulo":"Racionalizar gastos de software","cuerpo":"Rol: Eres analista de operaciones y finanzas especializado en optimización de costes tecnológicos (SaaS y licencias) en PyMEs.\nContexto: Actualmente pago por estas herramientas: [lista de herramientas y su función], con un coste total aproximado de [monto] al mes/año. Mi equipo es de [número] personas y el sector es [sector].\nTarea: Propón alternativas open-source, gratuitas o de consolidación (una herramienta que cubra varias funciones) para reducir ese gasto, evaluando funcionalidad, curva de aprendizaje y coste de migración.\nRestricciones: Señala siempre los compromisos de cada alternativa (funciones que se pierden, soporte, seguridad). No recomiendes migrar algo crítico sin advertir los riesgos. Verifica que las herramientas que menciones existan y no las inventes.\nFormato: Tabla comparativa: Herramienta actual | Coste | Alternativa | Coste estimado | Ahorro | Riesgo/compromiso. Termina con un plan de migración por fases y el ahorro total estimado como rango, no como cifra exacta."},
  {"id":"p78","catalogo":"prompts","grupo":"Por objetivos","tema":"Reducción de costes","titulo":"Estrategia Just-In-Time de inventario","cuerpo":"Rol: Eres experto en gestión de la cadena de suministro con enfoque en metodología Just-In-Time (JIT) y control de inventario para PyMEs.\nContexto: Gestiono el inventario de [producto]. Datos disponibles: demanda media [dato], plazo de entrega del proveedor [dato], coste de almacenamiento [dato] y frecuencia de roturas de stock [dato].\nTarea: Diseña una estrategia JIT orientada a reducir de forma significativa el coste de inventario manteniendo el nivel de servicio y minimizando el riesgo de roturas de stock.\nRestricciones: El objetivo de reducir el coste a la mitad es una meta, no una garantía; condiciona cualquier estimación a los supuestos y márgenes de seguridad. Advierte sobre los riesgos del JIT ante proveedores poco fiables o demanda volátil. Si faltan datos, pídelos.\nFormato: 1) Diagnóstico del riesgo actual. 2) Palancas de reducción de coste (stock de seguridad, lotes, acuerdos con proveedores). 3) Plan de implementación por etapas. 4) Indicadores a vigilar. 5) Supuestos usados."},
  {"id":"p79","catalogo":"prompts","grupo":"Por objetivos","tema":"Reducción de costes","titulo":"Script de envío de emails masivos","cuerpo":"Rol: Eres desarrollador especializado en Google Workspace y automatización con Google Apps Script.\nContexto: Tengo una hoja de Google Sheets con direcciones de correo en la columna A (una por fila, la primera fila es cabecera). Quiero enviar un email a cada dirección.\nTarea: Escribe una función de Google Apps Script, documentada y comentada, que recorra la columna A y envíe un email a cada dirección usando MailApp o GmailApp, con asunto y cuerpo configurables mediante variables al inicio.\nRestricciones: Incluye comentarios que expliquen cada bloque. Salta filas vacías y valida el formato de email antes de enviar. Advierte de forma explícita sobre los límites diarios de envío de Google y sobre no usarlo para spam ni sin consentimiento. No incluyas credenciales.\nFormato: 1) Bloque de código completo y listo para pegar en el editor de Apps Script. 2) Instrucciones numeradas de instalación y permisos. 3) Nota sobre límites de cuota y buenas prácticas de envío."},
  {"id":"p80","catalogo":"prompts","grupo":"Por objetivos","tema":"Reducción de costes","titulo":"SOP de 5 pasos para nuevos empleados","cuerpo":"Rol: Eres especialista en documentación operativa y diseño de procedimientos (SOP) para equipos en crecimiento.\nContexto: Necesito documentar la tarea [tarea] para que un empleado nuevo, sin experiencia previa, pueda ejecutarla de forma correcta y autónoma. Contexto adicional: [herramientas usadas, resultado esperado].\nTarea: Redacta un procedimiento operativo estándar (SOP) de exactamente 5 pasos, claro, secuencial y a prueba de errores.\nRestricciones: Usa lenguaje sencillo y directo, sin dar por supuesto conocimiento previo. Cada paso debe indicar qué hacer, con qué herramienta y cómo verificar que salió bien. Incluye errores comunes a evitar. No omitas pasos que parezcan obvios para un experto.\nFormato: Título del SOP, objetivo en una frase, responsable, y los 5 pasos numerados. Cada paso: acción, herramienta, criterio de verificación. Añade al final una checklist de control de calidad."},
  {"id":"p81","catalogo":"prompts","grupo":"Por objetivos","tema":"Expansión y GTM","titulo":"Plan Go-To-Market en 5 fases","cuerpo":"Rol: Eres estratega de Go-To-Market con experiencia en lanzamientos de producto en mercados hispanohablantes.\nContexto: Quiero lanzar [producto] en [región]. Información disponible: propuesta de valor [dato], presupuesto aproximado [dato], competencia [dato].\nTarea: Diseña un plan Go-To-Market en 5 fases que cubra público objetivo, canal de adquisición, precio inicial y KPIs por fase.\nRestricciones: Ajusta las tácticas al presupuesto y al contexto local de la región indicada. Justifica cada decisión con un razonamiento, no con afirmaciones genéricas. No prometas cifras de ventas; usa hipótesis y rangos. Señala los supuestos y los mayores riesgos.\nFormato: Una sección por fase (Fase 1 a 5) con: objetivo, público, canal, precio, KPIs y presupuesto orientativo. Cierra con una tabla resumen y las 3 métricas más importantes a vigilar."},
  {"id":"p82","catalogo":"prompts","grupo":"Por objetivos","tema":"Expansión y GTM","titulo":"Perfil psicográfico del buyer persona","cuerpo":"Rol: Eres investigador de mercado y estratega de marketing especializado en perfiles de cliente (buyer personas).\nContexto: Vendo [producto] dirigido a [describe brevemente el cliente y el mercado]. Quiero entender a fondo a quién le hablo.\nTarea: Construye un perfil psicográfico completo del buyer persona: demografía, objetivos, frustraciones (pain points), contenido y canales que consume, y objeciones de compra más probables.\nRestricciones: Marca con claridad qué partes son hipótesis razonables y cuáles requieren validación con datos reales o entrevistas. No presentes suposiciones como hechos. Mantén el perfil realista y basado en el contexto dado, sin estereotipos.\nFormato: Ficha de persona con: nombre ficticio, foto hablada (una frase), datos demográficos, objetivos, frustraciones, contenido que consume, objeciones y mensajes clave que las neutralizan. Añade una lista de preguntas para validar el perfil."},
  {"id":"p83","catalogo":"prompts","grupo":"Por objetivos","tema":"Expansión y GTM","titulo":"Barreras de entrada a un mercado","cuerpo":"Rol: Eres consultor en expansión internacional para e-commerce, con conocimiento de los mercados de LATAM y de comercio transfronterizo.\nContexto: Soy un e-commerce con base en LATAM que quiere entrar en el mercado de [país]. Mi categoría de producto es [categoría].\nTarea: Identifica y explica 5 barreras de entrada relevantes cubriendo dimensiones legales, culturales, logísticas y de competencia.\nRestricciones: Distingue entre datos generales y aspectos que dependen de normativa vigente que debe verificarse con una fuente oficial o un asesor local. No des asesoramiento legal ni fiscal definitivo. Prioriza las barreras por impacto.\nFormato: Lista numerada del 1 al 5. Cada barrera: tipo, descripción, por qué importa, y una acción de mitigación. Cierra con una advertencia sobre validar aspectos legales/fiscales con un profesional del país destino."},
  {"id":"p84","catalogo":"prompts","grupo":"Por objetivos","tema":"Expansión y GTM","titulo":"Freemium frente a prueba de 14 días","cuerpo":"Rol: Eres estratega de producto y monetización de SaaS con experiencia en modelos de adquisición y conversión.\nContexto: Lanzo un SaaS cuya función principal es [función], dirigido a [público]. Datos relevantes: coste de servir a un usuario gratuito [dato], ciclo de venta [dato], precio de pago [dato].\nTarea: Compara el modelo Freemium frente a la prueba gratuita de 14 días para este caso y recomienda cuál conviene, justificando la elección.\nRestricciones: Analiza ambos con sus ventajas y desventajas antes de recomendar; no presentes una opción como universalmente mejor. Basa la recomendación en el contexto y los datos dados. Señala qué métricas confirmarían o desmentirían la decisión.\nFormato: 1) Tabla comparativa (activación, conversión, coste, adecuación al producto). 2) Recomendación clara con su justificación. 3) Condiciones bajo las que cambiaría la recomendación. 4) Métricas a monitorear."},
  {"id":"p85","catalogo":"prompts","grupo":"Por objetivos","tema":"Expansión y GTM","titulo":"Alianzas locales para entrar en una ciudad","cuerpo":"Rol: Eres experto en desarrollo de negocio y alianzas estratégicas para expansión geográfica.\nContexto: Opero en el sector [sector] y quiero entrar en una nueva ciudad. Mi propuesta de valor es [dato] y mi cliente objetivo es [dato].\nTarea: Propón 5 tipos de alianzas locales que aceleren la entrada, describiendo para cada una la propuesta de valor cruzada (qué gana cada parte).\nRestricciones: Las alianzas deben ser realistas y equilibradas para ambas partes; evita esquemas en los que solo yo salga beneficiado. No prometas resultados; describe el mecanismo por el que cada alianza ayuda. Adapta las ideas al sector indicado.\nFormato: Lista numerada del 1 al 5. Cada tipo de alianza: aliado ideal, qué gana él, qué gano yo, primer paso para iniciarla. Termina con criterios para priorizar a qué aliado abordar primero."},
  {"id":"p86","catalogo":"prompts","grupo":"Por objetivos","tema":"Aprendizaje","titulo":"Explicar un concepto con la técnica Feynman","cuerpo":"Rol: Eres educador experto en la técnica Feynman y en explicar ideas complejas con claridad.\nContexto: Quiero entender de verdad el concepto [concepto], que aparece en el ámbito de [área/disciplina].\nTarea: Explica [concepto] en 3 niveles progresivos usando la técnica Feynman: 1) para un niño de 10 años, 2) para un estudiante universitario, 3) para un profesional del área.\nRestricciones: En el nivel infantil usa analogías cotidianas y evita toda jerga. En el universitario introduce los términos técnicos definiéndolos. En el profesional incluye matices, límites y errores comunes. No simplifiques hasta el punto de decir algo incorrecto.\nFormato: Tres secciones tituladas por nivel. Cada una con la explicación y una analogía o ejemplo. Cierra con una prueba de comprensión: 3 preguntas para autoevaluar si se entendió."},
  {"id":"p87","catalogo":"prompts","grupo":"Por objetivos","tema":"Aprendizaje","titulo":"Plan de estudio de 30 días","cuerpo":"Rol: Eres diseñador instruccional especializado en aprendizaje acelerado orientado a la práctica.\nContexto: Quiero dominar la habilidad [habilidad] en 30 días. Mi nivel actual es [principiante/intermedio], dispongo de [horas] al día y mi objetivo concreto es [dato].\nTarea: Crea un plan de estudio de 30 días con un proyecto o ejercicio de práctica diario y recursos recomendados, con dificultad creciente.\nRestricciones: Sé realista con lo alcanzable en 30 días para el nivel y las horas indicadas; no prometas maestría, sí progreso medible. Prioriza la práctica sobre la teoría pasiva. Recomienda solo recursos reales y verificables; si no estás seguro de uno, indícalo.\nFormato: Divide en 4 semanas con un tema por semana. Tabla por semana: Día | Objetivo | Proyecto/práctica | Recurso. Añade hitos de progreso al final de cada semana y una forma de medir el avance."},
  {"id":"p88","catalogo":"prompts","grupo":"Por objetivos","tema":"Aprendizaje","titulo":"Preguntas para aplicar un libro","cuerpo":"Rol: Eres coach de negocio experto en convertir la lectura en implementación práctica.\nContexto: Estoy leyendo el libro [libro] y quiero aplicar sus ideas a mi negocio, que es [describe tu negocio y su situación actual].\nTarea: Genera 10 preguntas de implementación práctica que me haga a mí mismo mientras leo, para traducir cada concepto clave del libro en acciones concretas para mi negocio.\nRestricciones: Las preguntas deben ser específicas y accionables, no genéricas ni retóricas. Enfócalas en decisiones y próximos pasos, no en resumir el libro. Si no conoces el contenido exacto del libro, indícalo y basa las preguntas en su tema general.\nFormato: Lista numerada del 1 al 10. Cada pregunta acompañada de una frase que explique qué decisión o acción busca desbloquear. Cierra sugiriendo cómo registrar las respuestas para pasar a la acción."},
  {"id":"p89","catalogo":"prompts","grupo":"Por objetivos","tema":"Aprendizaje","titulo":"Ejercicios de programación progresivos","cuerpo":"Rol: Eres instructor de programación con experiencia en enseñanza mediante ejercicios prácticos y comentados.\nContexto: Quiero practicar el tema [tema] en el lenguaje [lenguaje]. Mi nivel es [principiante/intermedio/avanzado].\nTarea: Diseña 3 ejercicios de programación de dificultad progresiva (fácil, medio y difícil) sobre ese tema, cada uno con su solución comentada paso a paso.\nRestricciones: Cada ejercicio debe construir sobre el anterior en dificultad. La solución debe explicar el razonamiento, no solo mostrar el código. Incluye casos borde en el nivel difícil. No des la solución antes del enunciado; sepáralas para que se pueda intentar primero.\nFormato: Para cada nivel: enunciado, entrada/salida esperada y pistas. Después, una sección separada 'Soluciones' con el código comentado y la explicación. Añade al final ideas para extender cada ejercicio."},
  {"id":"p90","catalogo":"prompts","grupo":"Por objetivos","tema":"Aprendizaje","titulo":"Curación de recursos sobre un tema","cuerpo":"Rol: Eres curador de contenidos y bibliotecario especializado en formación autodidacta de calidad.\nContexto: Quiero aprender en profundidad sobre [tema]. Mi nivel es [dato] y mi objetivo es [dato].\nTarea: Selecciona una lista curada de recursos: 3 libros, 3 newsletters y 2 cuentas de expertos a seguir, cada uno con una razón breve de por qué lo recomiendas.\nRestricciones: Recomienda solo recursos que existan realmente; no inventes títulos, autores ni enlaces. Si no tienes certeza de que un recurso esté vigente, adviértelo y sugiere verificarlo. Prioriza calidad y relevancia sobre popularidad. Evita recursos exclusivamente promocionales.\nFormato: Tres bloques (Libros, Newsletters, Cuentas de expertos). Cada ítem: nombre, autor/responsable, por qué lo recomiendo y para qué nivel. Cierra con una sugerencia de orden en el que consumirlos."},
  {"id":"p91","catalogo":"prompts","grupo":"Por objetivos","tema":"Estrategia","titulo":"Matriz de decisión ponderada","cuerpo":"Rol: Eres analista de decisiones experto en marcos de evaluación cuantitativa y priorización.\nContexto: Debo elegir entre [opción A] y [opción B] para [describe la decisión y su objetivo]. Datos relevantes de cada opción: [datos].\nTarea: Construye una matriz de decisión ponderada que puntúe ambas opciones en los criterios coste, tiempo, riesgo y escalabilidad, y calcula una recomendación.\nRestricciones: Pídeme o propón los pesos de cada criterio y justifícalos; no los fijes de forma arbitraria sin explicar. Aclara que el resultado depende de los pesos y de la calidad de los datos. No presentes la puntuación como una verdad objetiva, sino como una ayuda a la decisión.\nFormato: Tabla con criterios en filas y opciones en columnas: Peso | Puntuación A | Puntuación B | Ponderado A | Ponderado B. Muestra el total, la opción recomendada y un análisis de sensibilidad (qué pasaría si cambian los pesos)."},
  {"id":"p92","catalogo":"prompts","grupo":"Por objetivos","tema":"Estrategia","titulo":"Planificación de tres escenarios","cuerpo":"Rol: Eres estratega en planificación por escenarios y gestión de la incertidumbre.\nContexto: Quiero preparar mi negocio [negocio] frente al futuro. Variables clave que me preocupan: [ventas, costes, mercado, u otras]. Horizonte temporal: [dato].\nTarea: Desarrolla tres escenarios (optimista, neutro y pesimista) para el negocio, cada uno con sus supuestos, y define una acción clave a tomar en cada uno.\nRestricciones: Los escenarios deben ser coherentes y plausibles, no exageraciones. Explicita los supuestos de cada uno. No prediced el futuro con falsa precisión; usa rangos y señales de alerta temprana. Mantén cada acción concreta y ejecutable.\nFormato: Tres secciones (Optimista, Neutro, Pesimista). Cada una: supuestos, impacto esperado, señales que indican que se está cumpliendo y la acción clave. Cierra con las decisiones 'sin arrepentimiento' que conviene tomar pase lo que pase."},
  {"id":"p93","catalogo":"prompts","grupo":"Por objetivos","tema":"Estrategia","titulo":"OKRs trimestrales por departamento","cuerpo":"Rol: Eres coach de OKRs con experiencia implantando el marco en equipos y departamentos.\nContexto: Necesito definir los OKRs del próximo trimestre para el departamento de [área] en el sector [sector]. Prioridades actuales del negocio: [dato].\nTarea: Redacta 2 objetivos cualitativos e inspiradores y, para cada uno, 3 resultados clave medibles y con plazo trimestral.\nRestricciones: Los objetivos deben ser aspiracionales pero realistas; los resultados clave deben ser cuantificables y verificables, no tareas ni actividades. Evita métricas de vanidad. Alinea los OKRs con las prioridades del negocio indicadas. Si falta una línea base para medir, señálalo.\nFormato: Objetivo 1 con sus 3 resultados clave (con métrica, valor base y valor meta); Objetivo 2 con sus 3 resultados clave. Añade una nota sobre cómo hacer el seguimiento y una advertencia sobre no fijar más OKRs de los abarcables."},
  {"id":"p94","catalogo":"prompts","grupo":"Por objetivos","tema":"Estrategia","titulo":"Impacto de la IA generativa a 5 años","cuerpo":"Rol: Eres analista de tendencias tecnológicas especializado en el impacto de la IA generativa en distintos sectores.\nContexto: Trabajo en la industria [industria]. Quiero anticipar cómo la IA generativa la transformará en un horizonte de 5 años. Mi posición actual: [dato].\nTarea: Analiza el impacto a 5 años identificando 3 amenazas críticas y 3 oportunidades de negocio concretas para una empresa de este sector.\nRestricciones: Distingue entre tendencias razonablemente probables y especulación; etiqueta el nivel de certeza. No hagas predicciones deterministas ni des fechas exactas. Basa las oportunidades en capacidades reales de la tecnología, no en expectativas infladas. Evita el sensacionalismo.\nFormato: Dos bloques (Amenazas y Oportunidades), cada uno con 3 puntos numerados. Cada punto: descripción, por qué ocurriría, nivel de certeza (alto/medio/bajo) y una acción para prepararse. Cierra con las 3 apuestas prioritarias."},
  {"id":"p95","catalogo":"prompts","grupo":"Por objetivos","tema":"Estrategia","titulo":"Lean Canvas completo de una idea","cuerpo":"Rol: Eres mentor de startups experto en el marco Lean Canvas y validación temprana de modelos de negocio.\nContexto: Tengo la idea de negocio [negocio]. Información disponible: problema que resuelve [dato], cliente objetivo [dato], y lo que ya sé del mercado [dato].\nTarea: Desarrolla un Lean Canvas completo cubriendo sus 9 bloques: problema, segmentos de clientes, propuesta de valor única, solución, canales, fuentes de ingresos, estructura de costes, métricas clave y ventaja injusta.\nRestricciones: Señala qué bloques son hipótesis por validar y propón cómo validar cada uno. No rellenes bloques con afirmaciones vagas; si falta información, indícalo. Mantén la propuesta de valor honesta, sin promesas exageradas.\nFormato: Los 9 bloques, cada uno como sección con su contenido y una etiqueta [Validado] o [Por validar]. Cierra con las 3 hipótesis más arriesgadas y un experimento barato para probar cada una."},
  {"id":"p96","catalogo":"prompts","grupo":"Por objetivos","tema":"Marca personal","titulo":"Optimizar un perfil de LinkedIn","cuerpo":"Rol: Eres estratega de marca personal y experto en optimización de perfiles de LinkedIn para atracción de clientes.\nContexto: Mi rol profesional es [rol] y quiero atraer a [cliente ideal]. Mi propuesta de valor y logros principales son: [datos]. Mi titular y sección 'Acerca de' actuales son: [texto actual].\nTarea: Reescribe un titular magnético y una sección 'Acerca de' orientados a captar la atención del cliente ideal y comunicar mi valor.\nRestricciones: Basa el texto solo en logros y capacidades reales que te aporto; no inventes experiencia ni cifras. Evita la autopromoción vacía y los clichés. Escribe en primera persona, con lenguaje claro y una llamada a la acción sutil al final del 'Acerca de'.\nFormato: 1) Tres variantes de titular (menos de 220 caracteres). 2) Sección 'Acerca de' completa. 3) Lista breve de palabras clave para posicionamiento. 4) Una recomendación de qué prueba hacer para medir qué titular funciona mejor."},
  {"id":"p97","catalogo":"prompts","grupo":"Por objetivos","tema":"Marca personal","titulo":"Elevator pitch de 30 segundos","cuerpo":"Rol: Eres experto en comunicación persuasiva y en la construcción de discursos breves (elevator pitch).\nContexto: Necesito presentarme en 30 segundos. Datos: problema que resuelvo [dato], cómo lo resuelvo [dato], para quién [dato] y mi diferencial frente a otros [dato].\nTarea: Redacta un elevator pitch de unos 30 segundos (75-90 palabras) que cubra qué problema resuelvo, cómo, para quién y cuál es mi diferencial.\nRestricciones: Lenguaje natural y hablado, fácil de memorizar y decir en voz alta. Sin jerga innecesaria ni afirmaciones que no pueda respaldar. Evita superlativos vacíos; el diferencial debe ser específico y creíble. Cierra invitando a una conversación, no vendiendo de forma agresiva.\nFormato: 1) El pitch completo. 2) Una versión aún más corta de una frase (para presentaciones informales). 3) Consejos breves de entonación y pausas al decirlo."},
  {"id":"p98","catalogo":"prompts","grupo":"Por objetivos","tema":"Marca personal","titulo":"Mensaje de LinkedIn para pedir mentoría","cuerpo":"Rol: Eres experto en networking profesional y en comunicación escrita para relaciones de alto valor.\nContexto: Quiero contactar por LinkedIn a un directivo senior del área de [área] para pedirle mentoría. Sobre mí: [rol, logro reciente, por qué admiro su trayectoria]. Punto en común, si existe: [dato].\nTarea: Redacta un mensaje breve (menos de 400 caracteres) que pida mentoría de forma genuina, respetuosa del tiempo de la persona y sin tono servil ni adulador.\nRestricciones: Máximo 400 caracteres. Sé concreto en qué pides y por qué esa persona; nada de halagos vacíos. Facilita un 'sí' fácil (una pregunta puntual o una llamada corta). No presiones ni asumas disponibilidad. Tono de igual a igual, cordial y honesto.\nFormato: 1) El mensaje final con su recuento de caracteres. 2) Una variante alternativa de tono ligeramente distinto. 3) Nota sobre qué personalizar antes de enviarlo."},
  {"id":"p99","catalogo":"prompts","grupo":"Por objetivos","tema":"Marca personal","titulo":"Calendario semanal de LinkedIn","cuerpo":"Rol: Eres estratega de contenidos de LinkedIn especializado en posicionamiento como líder de opinión.\nContexto: Quiero posicionarme como referente en el sector [sector]. Mi rol es [dato], mis temas de dominio son [dato] y mi público objetivo es [dato].\nTarea: Diseña un calendario de 4 publicaciones semanales de LinkedIn, variando formatos y ángulos, que construya autoridad de forma sostenible.\nRestricciones: El plan debe ser realista de mantener para una sola persona; no propongas un ritmo insostenible. Prioriza aportar valor real sobre la autopromoción. Evita tácticas de interacción artificial (engagement bait). Adapta los temas al sector y público indicados.\nFormato: Tabla con: Día | Formato (texto, carrusel, encuesta, caso, etc.) | Tema/ángulo | Objetivo | Llamada a la acción. Añade 3 ganchos de apertura de ejemplo y una nota sobre cómo medir si el posicionamiento avanza."},
  {"id":"p100","catalogo":"prompts","grupo":"Por objetivos","tema":"Marca personal","titulo":"Pedir una recomendación profesional","cuerpo":"Rol: Eres experto en comunicación profesional y en el cuidado de relaciones laborales a largo plazo.\nContexto: Quiero pedir una recomendación a un ex-jefe o ex-cliente sobre el proyecto [proyecto]. Detalles: mi papel en el proyecto [dato], el resultado logrado [dato] y dónde quiero usar la recomendación [dato].\nTarea: Redacta un mensaje elegante y cordial para solicitar esa recomendación profesional, que se lo ponga fácil a la otra persona.\nRestricciones: Tono agradecido y respetuoso, sin sonar exigente ni dar la recomendación por hecha. Recuerda brevemente el contexto compartido y ofrece facilitar el trabajo (un borrador o puntos clave). No exageres logros; cíñete a lo real. Deja una salida cómoda por si la persona no puede.\nFormato: 1) Mensaje completo listo para enviar (email o LinkedIn). 2) Un borrador breve de puntos que puedo ofrecerle para que le sea más fácil escribir. 3) Nota sobre el momento adecuado para enviarlo y cómo agradecer después."},
];
